'use client'

import { useState, useRef, useEffect } from 'react'
import { Bot, Send, Loader2, Server, Shield, Zap, AlertTriangle, BookOpen } from 'lucide-react'

export default function AIAssistant() {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  const messagesEndRef = useRef(null)
  const inputRef = useRef(null)

  useEffect(() => {
    setMessages([{
      id: 'welcome',
      role: 'assistant',
      content: 'Ola! Sou seu assistente de IA para NOC.\n\nPosso ajudar com:\n- Configuracao de equipamentos (Huawei, Mikrotik, Cisco, Linux)\n- Troubleshooting de rede\n- Seguranca e firewall\n- Performance e otimizacao\n\nComo posso ajudá-lo?',
      timestamp: new Date(),
      suggestions: ['Verificar status da rede', 'Analisar segurança', 'Troubleshooting']
    }])
  }, [])

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const generateResponse = (query) => {
    const q = query.toLowerCase()

    if (q.includes('vlan')) {
      return '**Configuracao de VLAN**\n\n**Huawei:**\nsystem-view\nvlan 100\nname "Clientes"\ninterface GigabitEthernet0/0/1\nport link-type access\nport default vlan 100\n\n**Mikrotik:**\n/interface bridge vlan\nadd bridge=bridge1 tagged=ether1 vlan-ids=100'
    }

    if (q.includes('seguranca') || q.includes('security')) {
      return '**Seguranca de Rede ISP**\n\n1. DHCP Snooping - prevenir rogue DHCP\n2. Dynamic ARP Inspection\n3. BPDU Guard\n4. Firewall rules\n\n**Mikrotik exemplo:**\n/ip firewall filter\nadd chain=forward src-address=10.0.0.0/8 action=drop'
    }

    if (q.includes('problema') || q.includes('troubleshooting') || q.includes('sem internet')) {
      return '**Troubleshooting - Cliente sem Internet**\n\nPasso 1: Verificar ONU/ONT\n- Potencia optica (-8 a -27 dBm)\n- Status da porta\n\nPasso 2: Verificar VLAN\n- VLAN correta configurada\n- DHCP funcionando\n\nPasso 3: Comandos uteis\n- Huawei: display ont info\n- Mikrotik: ping, traceroute'
    }

    return 'Entendi sua pergunta sobre "' + query + '".\n\nSou especialista em redes ISP. Posso ajudar com configuracoes, troubleshooting, seguranca e performance.\n\nPode dar mais detalhes?'
  }

  const sendMessage = () => {
    if (!input.trim() || isLoading) return

    const userMessage = {
      id: 'user-' + Date.now(),
      role: 'user',
      content: input.trim(),
      timestamp: new Date()
    }

    setMessages(prev => [...prev, userMessage])
    setInput('')
    setIsLoading(true)

    setTimeout(() => {
      const response = generateResponse(input.trim())
      setMessages(prev => [...prev, {
        id: 'assistant-' + Date.now(),
        role: 'assistant',
        content: response,
        timestamp: new Date(),
        suggestions: ['Continuar', 'Mais detalhes', 'Ver documentacao']
      }])
      setIsLoading(false)
    }, 1000)
  }

  const handleQuickAction = (action) => {
    setInput(action)
    inputRef.current?.focus()
  }

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between bg-card border-b border-border px-6 py-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center">
            <Bot className="w-6 h-6 text-primary" />
          </div>
          <div>
            <h1 className="text-xl font-bold">Assistente IA NOC</h1>
            <p className="text-sm text-muted-foreground">Especialista em redes e infraestrutura</p>
          </div>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-auto p-6 space-y-4">
        {messages.map((message) => (
          <div
            key={message.id}
            className={'flex ' + (message.role === 'user' ? 'justify-end' : 'justify-start')}
          >
            <div
              className={'max-w-[80%] rounded-2xl px-4 py-3 ' + (message.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-card border border-border')}
            >
              <div className="whitespace-pre-wrap">{message.content}</div>

              {message.suggestions && (
                <div className="mt-3 pt-3 border-t border-border/50 flex flex-wrap gap-2">
                  {message.suggestions.map((s, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleQuickAction(s)}
                      className="px-3 py-1 text-sm bg-accent rounded-full hover:bg-accent/80"
                    >
                      {s}
                    </button>
                  ))}
                </div>
              )}

              <div className="text-xs mt-2 opacity-50">
                {message.timestamp.toLocaleTimeString()}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-card border border-border rounded-2xl px-4 py-3">
              <div className="flex items-center gap-2">
                <Loader2 className="w-4 h-4 animate-spin" />
                <span>Analisando...</span>
              </div>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Quick Actions */}
      <div className="px-6 py-2 border-t border-border flex gap-2 overflow-x-auto">
        <button onClick={() => handleQuickAction('Verificar status de todos equipamentos')} className="flex items-center gap-2 px-3 py-1.5 bg-accent rounded-lg text-sm whitespace-nowrap">
          <Server className="w-4 h-4" /> Status
        </button>
        <button onClick={() => handleQuickAction('Analisar segurança da rede')} className="flex items-center gap-2 px-3 py-1.5 bg-accent rounded-lg text-sm whitespace-nowrap">
          <Shield className="w-4 h-4" /> Seguranca
        </button>
        <button onClick={() => handleQuickAction('Dicas de otimização de performance')} className="flex items-center gap-2 px-3 py-1.5 bg-accent rounded-lg text-sm whitespace-nowrap">
          <Zap className="w-4 h-4" /> Performance
        </button>
        <button onClick={() => handleQuickAction('Troubleshooting passo a passo')} className="flex items-center gap-2 px-3 py-1.5 bg-accent rounded-lg text-sm whitespace-nowrap">
          <AlertTriangle className="w-4 h-4" /> Troubleshooting
        </button>
      </div>

      {/* Input */}
      <div className="p-4 border-t border-border">
        <div className="flex gap-3">
          <textarea
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault()
                sendMessage()
              }
            }}
            placeholder="Pergunte sobre redes, configuracoes, troubleshooting..."
            className="flex-1 px-4 py-3 bg-background border border-border rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-primary/50"
            rows={1}
          />
          <button
            onClick={sendMessage}
            disabled={isLoading || !input.trim()}
            className="px-4 py-3 bg-primary text-primary-foreground rounded-xl hover:bg-primary/90 disabled:opacity-50"
          >
            {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  )
}
